B.UH=new A.bT("A vida n\xe3o examinada n\xe3o vale a pena ser vivida.","S\xf3crates")
B.Uw=new A.bT("Somos o que fazemos repetidamente. Excel\xeancia, ent\xe3o, n\xe3o \xe9 um ato, mas um h\xe1bito.","Arist\xf3teles")
B.Uf=new A.bT("Voc\xea tem poder sobre sua mente, n\xe3o sobre os eventos externos. Perceba isso e encontrar\xe1 for\xe7a.","Marco Aur\xe9lio")
B.U7=new A.bT("O que n\xe3o me mata, me fortalece.","Friedrich Nietzsche")
B.UJ=new A.bT("A imagina\xe7\xe3o \xe9 mais importante que o conhecimento.","Albert Einstein")
B.Ue=new A.bT("A jornada de mil milhas come\xe7a com um \xfanico passo.","Lao Tzu")
B.Uu=new A.bT("N\xe3o \xe9 o que acontece com voc\xea, mas como voc\xea reage ao que acontece com voc\xea que importa.","Epicteto")
B.Us=new A.bT("A raiz da educa\xe7\xe3o \xe9 amarga, mas seus frutos s\xe3o doces.","Arist\xf3teles")
B.UB=new A.bT("A melhor vingan\xe7a \xe9 n\xe3o ser como seu inimigo.","Marco Aur\xe9lio")
B.Ul=new A.bT("A mudan\xe7a \xe9 a \xfanica constante da vida.","Her\xe1clito")
B.Ub=new A.bT("O segredo da mudan\xe7a \xe9 focar toda a sua energia n\xe3o em lutar contra o velho, mas em construir o novo.","S\xf3crates")
B.Uc=new A.bT("Aquele que tem um porqu\xea para viver suporta quase qualquer como.","Friedrich Nietzsche")
B.Ur=new A.bT("Penso, logo existo.","Ren\xe9 Descartes")
B.Up=new A.bT("A felicidade \xe9 o significado e o prop\xf3sito da vida, o objetivo e o fim da exist\xeancia humana.","Arist\xf3teles")
B.Uy=new A.bT("Nunca confunda movimento com a\xe7\xe3o.","Ernest Hemingway")
B.Uo=new A.bT("Comece onde voc\xea est\xe1. Use o que voc\xea tem. Fa\xe7a o que voc\xea pode.","Arthur Ashe")
B.UK=new A.bT("A disciplina \xe9 a ponte entre metas e conquistas.","Jim Rohn")
B.UC=new A.bT("O sucesso \xe9 a soma de pequenos esfor\xe7os repetidos dia ap\xf3s dia.","Robert Collier")
B.U8=new A.bT("N\xe3o espere. O momento nunca ser\xe1 perfeito.","Napoleon Hill")
B.U6=new A.bT("O homem est\xe1 condenado a ser livre.","Jean-Paul Sartre")
B.UG=new A.bT("Trate um homem como ele pode se tornar e voc\xea o tornar\xe1 no que ele pode ser.","Goethe")
B.UI=new A.bT("No meio de toda dificuldade h\xe1 uma oportunidade.","Albert Einstein")
B.Uq=new A.bT("A vida \xe9 10% o que acontece comigo e 90% como eu reajo a isso.","Charles R. Swindoll")
B.Uv=new A.bT("O que voc\xea pensa, voc\xea se torna. O que voc\xea sente, voc\xea atrai. O que voc\xea imagina, voc\xea cria.","Buda")
B.Ug=new A.bT("Conhece-te a ti mesmo.","S\xf3crates")
B.UA=new A.bT("A \xfanica maneira de fazer um \xf3timo trabalho \xe9 amar o que voc\xea faz.","Steve Jobs")
B.Ux=new A.bT("N\xe3o \xe9 poss\xedvel pisar duas vezes no mesmo rio.","Her\xe1clito")
B.Ud=new A.bT("Age de tal forma que a m\xe1xima de tua vontade possa valer como princ\xedpio de uma legisla\xe7\xe3o universal.","Immanuel Kant")
B.UD=new A.bT("A grandeza do homem est\xe1 em ser uma ponte, n\xe3o um fim.","Friedrich Nietzsche")
B.Um=new A.bT("S\xf3 sei que nada sei.","S\xf3crates")
B.Uz=new A.bT("O tempo que voc\xea gosta de perder n\xe3o \xe9 tempo perdido.","Bertrand Russell")
B.Uk=new A.bT("Sua vida n\xe3o \xe9 um acidente. \xc9 um reflexo de suas decis\xf5es.","Tony Robbins")
B.Ut=new A.bT("A exist\xeancia precede a ess\xeancia.","Jean-Paul Sartre")
B.Un=new A.bT("A mente que se abre a uma nova ideia jamais voltar\xe1 ao seu tamanho original.","Albert Einstein")
B.U5=new A.bT("Fazer o bem por obriga\xe7\xe3o \xe9 virtude; fazer o bem por amor \xe9 sabedoria.","Conf\xfacio")
B.UF=new A.bT("Onde a disposi\xe7\xe3o existe, os meios geralmente se seguem.","George S. Patton")
B.Ua=new A.bT("N\xe3o importa qu\xe3o devagar voc\xea v\xe1, desde que n\xe3o pare.","Conf\xfacio")
B.Uh=new A.bT("O homem s\xe1bio n\xe3o diz tudo que pensa, mas sempre pensa tudo que diz.","Arist\xf3teles")
